// ============================================================
// migrate-products.js — Convert product .json files to .md
// so that Decap CMS can manage all products (create, edit, delete)
//
// Usage:  node scripts/migrate-products.js [--dry-run]
//
// After migration, .json files are auto-generated by
// generate-index.js from the .md frontmatter.
// ============================================================

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const projectRoot = path.resolve(__dirname, "..");
const productsDir = path.join(projectRoot, "content", "products");

const dryRun = process.argv.includes("--dry-run");

// ============================================================
// YAML serializer — handles strings, numbers, booleans,
// arrays, and nested objects
// ============================================================

function yamlValue(val, indent) {
  if (val === null || val === undefined) return "null";
  if (typeof val === "boolean") return val ? "true" : "false";
  if (typeof val === "number") return String(val);
  if (typeof val === "string") return yamlString(val);
  if (Array.isArray(val)) return yamlArray(val, indent);
  if (typeof val === "object") return yamlObject(val, indent);
  return String(val);
}

function yamlString(str) {
  // Always quote strings to avoid YAML parsing issues
  // Use double quotes and escape internal quotes/backslashes
  const escaped = str.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
  return `"${escaped}"`;
}

function yamlArray(arr, indent) {
  if (arr.length === 0) return "[]";
  const prefix = "  ".repeat(indent);
  const lines = arr.map((item) => {
    if (typeof item === "string") {
      return `${prefix}- ${yamlString(item)}`;
    }
    if (typeof item === "number" || typeof item === "boolean") {
      return `${prefix}- ${yamlValue(item, 0)}`;
    }
    if (typeof item === "object" && item !== null) {
      // Array of objects — render inline on one line if simple
      const keys = Object.keys(item);
      if (keys.length === 1) {
        return `${prefix}- ${keys[0]}: ${yamlValue(item[keys[0]], 0)}`;
      }
      // Multi-key object
      const first = `${prefix}- ${keys[0]}: ${yamlValue(item[keys[0]], 0)}`;
      const rest = keys.slice(1).map((k) => `${prefix}  ${k}: ${yamlValue(item[k], 0)}`);
      return [first, ...rest].join("\n");
    }
    return `${prefix}- ${String(item)}`;
  });
  return "\n" + lines.join("\n");
}

function yamlObject(obj, indent) {
  const prefix = "  ".repeat(indent);
  const keys = Object.keys(obj);
  if (keys.length === 0) return "{}";
  const lines = keys.map((key) => {
    const val = obj[key];
    if (typeof val === "object" && val !== null && !Array.isArray(val)) {
      // Nested object — recurse
      return `${prefix}${key}:\n${yamlObject(val, indent + 1)}`;
    }
    if (Array.isArray(val)) {
      return `${prefix}${key}:\n${yamlArray(val, indent + 1)}`;
    }
    return `${prefix}${key}: ${yamlValue(val, 0)}`;
  });
  return lines.join("\n");
}

// ============================================================
// Build YAML frontmatter from product data
// ============================================================

function buildFrontmatter(data) {
  // Define field order matching config.yml
  const fieldOrder = [
    "name", "sku", "category", "categoryLabel", "brand",
    "price", "compareAtPrice", "image", "images",
    "tagline", "description", "userBenefits",
    "specs", "compliance",
    "inStock", "stock", "moq", "leadTime", "warranty",
    "featured", "isFeatured", "isTopProduct",
    "rating", "reviewCount",
    "relatedProducts", "downloads",
  ];

  const lines = ["---"];

  // Write fields in defined order
  for (const key of fieldOrder) {
    if (!(key in data)) continue;
    const val = data[key];

    if (typeof val === "object" && val !== null && !Array.isArray(val)) {
      lines.push(`${key}:`);
      lines.push(yamlObject(val, 1));
    } else if (Array.isArray(val)) {
      if (val.length === 0) {
        lines.push(`${key}: []`);
      } else {
        lines.push(`${key}:`);
        lines.push(yamlArray(val, 1));
      }
    } else {
      lines.push(`${key}: ${yamlValue(val, 0)}`);
    }
  }

  // Write any remaining fields not in the defined order
  for (const key of Object.keys(data)) {
    if (fieldOrder.includes(key)) continue;
    const val = data[key];
    if (typeof val === "object" && val !== null && !Array.isArray(val)) {
      lines.push(`${key}:`);
      lines.push(yamlObject(val, 1));
    } else if (Array.isArray(val)) {
      lines.push(`${key}:`);
      lines.push(yamlArray(val, 1));
    } else {
      lines.push(`${key}: ${yamlValue(val, 0)}`);
    }
  }

  lines.push("---");
  return lines.join("\n");
}

// ============================================================
// Main
// ============================================================

console.log(`Product JSON → MD Migration (${dryRun ? "DRY RUN" : "LIVE"})\n`);

const jsonFiles = fs.readdirSync(productsDir).filter(
  (f) => f.startsWith("SY-") && f.endsWith(".json")
);

console.log(`Found ${jsonFiles.length} product JSON files\n`);

let migrated = 0;
let skipped = 0;
let errors = 0;

for (const file of jsonFiles) {
  const jsonPath = path.join(productsDir, file);
  const sku = file.replace(".json", "");
  const mdPath = path.join(productsDir, `${sku}.md`);

  // Skip if .md already exists (don't overwrite)
  if (fs.existsSync(mdPath)) {
    console.log(`  SKIP ${sku}.md already exists`);
    skipped++;
    continue;
  }

  try {
    const raw = fs.readFileSync(jsonPath, "utf-8");
    const data = JSON.parse(raw.replace(/^\uFEFF/, ""));

    const frontmatter = buildFrontmatter(data);
    const mdContent = frontmatter + "\n";

    if (dryRun) {
      console.log(`  WOULD CREATE ${sku}.md (${mdContent.split("\n").length} lines)`);
    } else {
      fs.writeFileSync(mdPath, mdContent, "utf-8");
      console.log(`  CREATED ${sku}.md`);
    }
    migrated++;
  } catch (err) {
    console.error(`  ERROR ${file}: ${err.message}`);
    errors++;
  }
}

console.log(`\nResults: ${migrated} migrated, ${skipped} skipped, ${errors} errors`);

if (!dryRun && migrated > 0) {
  console.log("\nNext steps:");
  console.log("  1. Run: node scripts/generate-index.js");
  console.log("  2. Verify all products still appear in the website");
  console.log("  3. Add SY-*.json to .gitignore (auto-generated from .md)");
}
